import sys
it = iter(sys.stdin.read().split())
n = int(next(it))
s = next(it)
def atoi(s, index, sign, num):
    if index == len(s):
        return int(sign * num)
    if s[index].isdigit():
        num = num * 10 + int(s[index])
        if sign * num > 2**31 - 1:
            return 2**31 - 1
        elif sign * num < -2**31:
            return -2**31
        return atoi(s, index + 1, sign, num)
    else:
        return int(sign * num)
def solve(s):
    index = 0
    while index < len(s) and s[index] == ' ':
        index += 1
    sign = 1
    if index < len(s) and s[index] == '-':
        sign = -1
        index += 1
    elif index < len(s) and s[index] == '+':
        index += 1
    return atoi(s, index, sign, 0)
print(solve(s))

