#include <bits/stdc++.h>
using namespace std;
long long atoi(string s, int index, long long sign, long long num) {
    if (index == s.length()) {
        return sign * num;
    }
    if (isdigit(s[index])) {
        num = num * 10 + (s[index] - '0');
        if (sign * num > (1LL << 31) - 1) {
            return (1LL << 31) - 1;
        } else if (sign * num < -(1LL << 31)) {
            return -(1LL << 31);
        }
        return atoi(s, index + 1, sign, num);
    } else {
        return sign * num;
    }
}
int main() {
    int n;
    cin >> n;
    string s;
    cin >> s;
    int index = 0;
    while (index < s.length() && s[index] == ' ') {
        index++;
    }
    long long sign = 1;
    if (index < s.length() && s[index] == '-') {
        sign = -1;
        index++;
    } else if (index < s.length() && s[index] == '+') {
        index++;
    }
    cout << atoi(s, index, sign, 0) << endl;
    return 0;
}
